  function activeSectionHighlightValue(){const fallback=normalizeHex(DATA?.brand?.primaryColor||$('brand_primaryColor')?.value,'#19aeb6');return normalizeHex($('brand_activeSectionHighlightColor')?.value||DATA?.brand?.activeSectionHighlightColor,fallback)}
