  async function createCompleteBackup(){const btn=$('completeBackupBtn'),msg=$('completeBackupStatus');if(btn)btn.disabled=true;if(msg)msg.textContent='Creating complete backup set...';try{const d=await api('/api/backups/full',{method:'POST',body:'{}'});await renderBackup(d.backups);alert(`Complete backup created for ${d.backedUp.length} data area${d.backedUp.length===1?'':'s'}. Restore target "Everything, latest available" will use this matched set.`)}catch(e){if(msg)msg.textContent=e.message||'Complete backup failed.';alert(e.message||'Complete backup failed.')}finally{if(btn)btn.disabled=false}}
