  function renderRoles(){if(!hasAdmin()||!$('userRolesCenter'))return;$('userRolesCenter').innerHTML=`<br><div class="callout"><h3>SOP Assignment Roles</h3><p class="small">These roles filter Staff Portal My SOPs and fill the SOP Editor assignment dropdown. They do not restrict direct SOP, PDF, or attachment access. Permissions stay fixed as ${html(state.accessRoles.join(', '))}.</p><textarea id="roleText" class="jsonarea" style="min-height:150px">${html(state.roles.join('\n'))}</textarea><div class="toolbar"><button class="btn primary" id="saveRolesBtn">Save SOP Assignment Roles</button></div></div>`;$('saveRolesBtn').onclick=async()=>{state.roles=(await api('/api/roles',{method:'PUT',body:JSON.stringify({roles:$('roleText').value.split(/\r?\n/).map(x=>x.trim()).filter(Boolean)})})).roles;renderRoles();renderUserSopRoles();renderSopRoleSelect();status.textContent='SOP assignment roles updated.'}}
