function renderAdvancedReset(){if(!hasAdmin()||!$('advancedResetCenter'))return;const versions=portalVersions(),qrUrl=PORTAL.qrCodeApiUrl||'https://api.qrserver.com/v1/create-qr-code/?size=260x260&data={DATA}';$('advancedResetCenter').innerHTML=`<div class="callout"><h3>QR Code API Connection</h3><p class="small">QR codes use this image API. Use {DATA} where the encoded SOP link should go.</p><div class="form-grid"><div class="field full"><label>QR Code API URL</label><input id="qrCodeApiUrl" value="${html(qrUrl)}"></div><div class="field full"><button type="button" class="btn secondary" id="saveQrCodeApiBtn">Save QR Code API</button></div></div><p class="small" id="qrCodeApiStatus"></p></div><br><div class="callout warning"><h3>Start Over / Restore Snapshot</h3><p>These tools are for new customer setup and major data repair. A full backup and whole-portal SOP snapshot are created before clearing or restoring.</p><div class="toolbar"><button type="button" class="btn danger" id="clearAllSopsBtn">Remove All Sections and SOPs</button><button type="button" class="btn secondary" id="restoreSnapshotBtn">Restore Snapshot</button></div><p class="small">Select a snapshot from All SOPs Version History / Rollback below, then choose Restore Snapshot.</p><label class="small" style="display:block;margin-top:10px"><input type="checkbox" id="clearCustomData"> Also clear staff custom data: pinned SOPs, checklist runs, quiz/read results, generator history, and change requests</label></div><br><h3>All SOPs Version History / Rollback</h3><div class="version-list">${versions.length?versions.map(v=>`<div class="version-row ${state.portalVersionId===v.id?'active':''}" onclick="selectPortalVersion('${html(v.id)}')"><b>${html(v.action)} - ${html(new Date(v.timestamp).toLocaleString())}</b><div class="small">${html(v.summary||'Whole portal snapshot')} - ${v.counts?.sections||0} sections - ${v.counts?.sops||0} SOPs - ${html(v.editor||'')}</div></div>`).join(''):'<p class="small">No whole-portal SOP snapshots yet.</p>'}</div><div class="toolbar" style="margin-top:10px"><button type="button" class="btn secondary" id="createPortalSnapshotBtn">Create Snapshot</button><button type="button" class="btn danger" id="clearPortalSnapshotsBtn">Clear Snapshots</button></div>`;$('saveQrCodeApiBtn').onclick=saveQrCodeApi;$('createPortalSnapshotBtn').onclick=async()=>{portalSnapshot('Manual Snapshot','Manual whole-portal SOP and section snapshot.');await savePortalReset('Whole-portal snapshot saved.')};$('clearAllSopsBtn').onclick=clearAllSops;$('restoreSnapshotBtn').onclick=rollbackPortalSnapshot;$('clearPortalSnapshotsBtn').onclick=clearPortalSnapshots}
