  async function clearPortalSnapshots(){if(prompt('Type CLEAR to delete all whole-portal snapshots.')!=='CLEAR')return alert('Clear snapshots cancelled.');DATA.settings=DATA.settings||{};DATA.settings.portalVersions=[];state.portalVersionId='';await savePortalReset('Whole-portal snapshots cleared.')}
