  function uniq(list){const seen=new Set(),out=[];for(const item of list.map(x=>String(x||'').trim()).filter(Boolean)){const k=item.toLowerCase();if(!seen.has(k)){seen.add(k);out.push(item)}}return out}
  function mcQuestion(question,answer,pool=[]){const fallbacks=['Ask a manager before proceeding','Skip the SOP step','Use a different SOP','Mark the task complete without review'];let choices=uniq([answer,...pool,...fallbacks]).filter(x=>x!==String(answer||'').trim()).slice(0,3);choices=uniq([answer,...choices]).slice(0,4);while(choices.length<4)choices.push(`Option ${choices.length+1}`);const offset=String(question||'').length%choices.length;return{question,answer,choices:[...choices.slice(offset),...choices.slice(0,offset)]}}
  function quizRows(){return [...document.querySelectorAll('#quizBuilder .quiz-row')].map(row=>{const question=row.querySelector('[data-q]')?.value.trim()||'',answer=row.querySelector('[data-a]')?.value.trim()||'',choices=uniq([...row.querySelectorAll('[data-c]')].map(x=>x.value).concat(answer));return{question,answer,choices}}).filter(q=>q.question&&q.answer)}
  function addQuizRow(q={question:'',answer:'',choices:[]}){const wrap=$('quizBuilder');if(!wrap)return;const choices=uniq([...(q.choices||q.options||[]),q.answer]).slice(0,4);while(choices.length<4)choices.push('');wrap.insertAdjacentHTML('beforeend',`<div class="quiz-row"><div class="field full"><label>Question</label><input data-q value="${html(q.question)}" placeholder="What should the staff member know?"></div><div class="field"><label>Correct answer</label><input data-a value="${html(q.answer)}" placeholder="Correct multiple-choice answer"></div><div class="quiz-choice-grid">${choices.map((c,i)=>`<div class="field"><label>Choice ${i+1}</label><input data-c value="${html(c)}" placeholder="${i?'Incorrect option':'Include correct answer'}"></div>`).join('')}</div><button type="button" class="btn danger" data-remove-quiz>Remove</button></div>`);wrap.querySelectorAll('[data-remove-quiz]').forEach(b=>b.onclick=()=>b.closest('.quiz-row')?.remove())}
  function builtQuizFromSop(sop){const out=[],sections=(DATA.sections||[]).map(s=>s.title),owners=uniq((DATA.sops||[]).map(s=>s.owner)),roles=uniq(['All Staff',...state.roles]),steps=sop.steps||[];if(sop.owner)out.push(mcQuestion('Who owns this SOP?',sop.owner,owners));if(sop.sectionId)out.push(mcQuestion('Which section does this SOP belong to?',sectionTitle(sop.sectionId),sections));if(sop.roles)out.push(mcQuestion('Which staff assignment role uses this SOP?',sop.roles,roles));if((sop.steps||[])[0])out.push(mcQuestion('What is the first step in this SOP?',sop.steps[0],steps.slice(1,5)));if(sop.validation)out.push(mcQuestion('How do you confirm this SOP is complete?',sop.validation,['Confirm with the validation standard in the SOP','Skip validation if the client is waiting','Only check the first step','Use any method that feels fastest']));return out.slice(0,6)}
  function stepQuizFromSop(sop){const steps=sop.steps||[];return steps.slice(0,8).map((step,i)=>mcQuestion(`Which option is step ${i+1}?`,step,steps.filter(x=>x!==step)))}
  function trainingResultText(r){const isRead=r.confirmed&&(!Array.isArray(r.answers)||!r.answers.length);return isRead?'Read Confirmation':(r.total?`${r.score}% - ${r.correct}/${r.total} correct`:'Completion saved')}
  function renderTraining(){const current=DATA?.sops?.find(s=>s.id===(state.trainingSopId||currentSopId))||currentSop();state.trainingSopId=current?.id;const allRuns=Array.isArray(state.runs)?state.runs:[],allTraining=Array.isArray(state.training)?state.training:[],runs=allRuns.filter(r=>!current||r.sopId===current.id),results=allTraining.filter(r=>!current||r.sopId===current.id);$('trainingCenter').innerHTML=`<div class="training-layout"><div class="training-builder"><div class="form-grid"><div class="field full"><label>Build training for SOP</label><select id="trainingSopSelect">${sopOptions()}</select></div></div><div class="callout"><h3>${html(current?.id||'')} - ${html(current?.title||'Select an SOP')}</h3><p class="small">${html(current?.purpose||'Choose an SOP to build multiple-choice quiz questions and preview checklist steps from existing SOP data.')}</p><div class="meta-grid"><div class="meta-card"><b>Owner</b><span>${html(current?.owner||'')}</span></div><div class="meta-card"><b>Assignment Role</b><span>${html(current?.roles||'')}</span></div><div class="meta-card"><b>Prerequisites</b><span>${html(current?.prerequisites||'')}</span></div><div class="meta-card"><b>Validation</b><span>${html(current?.validation||'')}</span></div></div></div><h3>Checklist Preview</h3><p class="small">Staff checklist runs are created automatically from the SOP steps below. Edit the SOP steps in SOP Editor if this checklist needs to change.</p><ol class="steps training-step-preview">${(current?.steps||[]).map(x=>`<li>${html(x)}</li>`).join('')||'<li>No steps found.</li>'}</ol><h3>Multiple-Choice Quiz Builder</h3><p class="small">Build answer choices from the selected SOP, then adjust wording before saving.</p><div class="toolbar"><button type="button" class="btn secondary" id="buildSummaryQuizBtn">Build from SOP Fields</button><button type="button" class="btn secondary" id="buildStepQuizBtn">Build from Steps</button><button type="button" class="btn secondary" id="addQuizBtn">Add Question</button><button type="button" class="btn secondary" id="clearQuizBtn">Clear</button></div><div id="quizBuilder" class="quiz-builder"></div><div class="toolbar" style="margin-top:12px"><button class="btn primary" id="saveQuizBtn">Save Quiz to SOP</button><button class="btn secondary" id="openTrainingSopBtn">Open SOP Editor</button></div></div><div class="training-reports"><h3>Recent Checklist Runs for This SOP</h3><p class="small">${runs.length} shown for this SOP &middot; ${allRuns.length} total checklist runs</p><div class="version-list">${runs.slice(0,40).map(r=>`<div class="version-row"><b>${html(r.userName)}</b><div class="small">${html(new Date(r.createdAt).toLocaleString())} &middot; ${r.completed?'Completed':'In progress'} &middot; ${(r.checked||[]).length} checked</div>${r.notes?`<p class="small">${html(r.notes)}</p>`:''}</div>`).join('')||'<p class="small">No checklist runs saved for this SOP yet.</p>'}</div><h3>Recent Quiz Results / Read Confirmations for This SOP</h3><p class="small">${results.length} shown for this SOP &middot; ${allTraining.length} total training records</p><div class="version-list">${results.slice(0,40).map(r=>`<div class="version-row"><b>${html(r.userName)}</b><div class="small">${html(new Date(r.createdAt).toLocaleString())} - ${html(trainingResultText(r))}</div></div>`).join('')||'<p class="small">No quiz results or read confirmations saved for this SOP yet.</p>'}</div></div></div>`;$('trainingSopSelect').value=current?.id||'';$('trainingSopSelect').onchange=e=>{state.trainingSopId=e.target.value;renderTraining()};(current?.quiz||[]).forEach(addQuizRow);if(!(current?.quiz||[]).length)builtQuizFromSop(current||{}).forEach(addQuizRow);$('buildSummaryQuizBtn').onclick=()=>{$('quizBuilder').innerHTML='';builtQuizFromSop(current||{}).forEach(addQuizRow)};$('buildStepQuizBtn').onclick=()=>{$('quizBuilder').innerHTML='';stepQuizFromSop(current||{}).forEach(addQuizRow)};$('addQuizBtn').onclick=()=>addQuizRow();$('clearQuizBtn').onclick=()=>{$('quizBuilder').innerHTML=''};$('openTrainingSopBtn').onclick=()=>{currentSopId=current.id;setTab('sops');renderSopList();renderSopForm()};$('saveQuizBtn').onclick=async()=>{if(!current)return;const quiz=quizRows();try{const d=await api('/api/sop-quiz',{method:'PUT',body:JSON.stringify({sopId:current.id,quiz})});current.quiz=d.sop?.quiz||quiz;if(d.dataVersion)DATA._dataVersion=d.dataVersion;SAVED_DATA=JSON.parse(JSON.stringify(DATA));syncJson();state.trainingSopId=current.id;status.textContent=`Saved ${current.quiz.length} quiz question${current.quiz.length===1?'':'s'} for ${current.id}.`;renderTraining()}catch(e){alert(e.message||'Quiz save failed.')}}}
  function duplicateIntoSection(){if(saveSop(false)===false)return;const s=currentSop();if(!s)return;const target=prompt('Duplicate into which section ID? Leave blank to use current section.\n\nAvailable:\n'+DATA.sections.map(x=>`${x.id} - ${x.title}`).join('\n'),s.sectionId);if(target===null)return;const sid=DATA.sections.some(x=>x.id===target)?target:s.sectionId;const c=JSON.parse(JSON.stringify(s));c.id=uniqueId(s.id+'-COPY');c.title=s.title+' Copy';c.sectionId=sid;c.status='Draft';c.attachments=[];c.versions=[];DATA.sops.push(c);currentSopId=c.id;recordVersion(c,'Duplicated','Duplicated SOP into section.');renderAll();syncJson()}
  async function archiveCurrentSop(){if(!MANAGER_ROLES.includes(ME.role))return alert('Manager/Admin required.');const s=currentSop();if(!s)return;if(!confirm(`Archive ${s.id} - ${s.title}? It will leave the staff portal but stay in Archive.`))return;const original=JSON.parse(JSON.stringify(DATA));sop_status.value='Archived';if(saveSop(true,'Archived')===false)return;const saved=await publish();if(saved===false){DATA=original;SAVED_DATA=JSON.parse(JSON.stringify(original));renderAll();syncJson();status.textContent='Archive was not saved. The SOP was restored in the editor.';return}await loadData();setTab('archive');status.textContent=`Archived ${s.id}.`}
  function patchUserActions(){if(!hasAdmin()||!$('createUserBtn'))return;window.selectUser=selectUser=function(username){selectedUsername=username;const u=USERS.find(x=>x.username===username);if(!u)return;user_username.value=u.username;user_displayName.value=u.displayName;user_role.value=u.role;user_active.value=String(u.active!==false);user_password.value='';renderUsers();enhanceUsers();renderUserSopRoles()};window.clearUser=clearUser=function(){selectedUsername=null;user_username.value='';user_displayName.value='';user_role.value='Staff';user_active.value='true';user_password.value='';renderUsers();enhanceUsers();renderUserSopRoles()};if($('clearUserBtn'))clearUserBtn.onclick=()=>clearUser();createUserBtn.onclick=async()=>{const payload={username:user_username.value,displayName:user_displayName.value,role:user_role.value,sopRoles:selectedUserSopRoles(),active:user_active.value==='true',password:user_password.value};const r=await fetch('/api/users',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Create failed');USERS=d.users;selectedUsername=payload.username;user_password.value='';renderUsers();enhanceUsers();renderDashboard()};updateUserBtn.onclick=async()=>{if(!selectedUsername)return alert('Select a user first.');const p={username:selectedUsername,displayName:user_displayName.value,role:user_role.value,sopRoles:selectedUserSopRoles(),active:user_active.value==='true'};if(user_password.value)p.password=user_password.value;const r=await fetch('/api/users',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(p)});const d=await r.json().catch(()=>({}));if(!r.ok)return alert(d.error||'Update failed');USERS=d.users;user_password.value='';renderUsers();enhanceUsers();renderDashboard()}}
  function enhanceImportDedupe(){const oldRender=window.renderImportPreview||renderImportPreview;window.renderImportPreview=renderImportPreview=function(){oldRender();if(!IMPORT_PREVIEW?.sops?.length)return;document.querySelectorAll('#importPreview .sop-admin-item').forEach((el,i)=>{const item=IMPORT_PREVIEW.sops[i],dup=DATA.sops.find(s=>s.id===item.id||String(s.title).toLowerCase()===String(item.title).toLowerCase());if(dup&&!el.querySelector('.dedupe-action'))el.insertAdjacentHTML('beforeend',`<div class="field dedupe-action"><label>Duplicate found: ${html(dup.id)} - ${html(dup.title)}</label><select data-import-action="${i}"><option value="add">Add new copy</option><option value="skip">Skip</option><option value="update">Update existing as draft</option></select></div>`)})};const oldSave=window.saveImported||saveImported;window.saveImported=saveImported=async function(statusValue){if(!IMPORT_PREVIEW.sops.length)parseImportResult();const actions=[...document.querySelectorAll('[data-import-action]')].reduce((m,x)=>(m[x.dataset.importAction]=x.value,m),{});const updates=[];IMPORT_PREVIEW.sops=IMPORT_PREVIEW.sops.filter((item,i)=>{const dup=DATA.sops.find(s=>String(s.title).toLowerCase()===String(item.title).toLowerCase());if(actions[i]==='skip')return false;if(actions[i]==='update'&&dup){Object.assign(dup,{status:'Draft',title:item.title,purpose:item.purpose,scope:item.scope,prerequisites:item.prerequisites,steps:item.steps,validation:item.validation,exceptions:item.exceptions,owner:item.owner,roles:item.roles,tags:item.tags});updates.push(dup.id);return false}return true});if(updates.length){renderAll();syncJson();await publish();status.textContent=`Updated ${updates.length} duplicate SOP draft${updates.length===1?'':'s'}.`}if(IMPORT_PREVIEW.sops.length)return oldSave(statusValue)}}
  function patchFunctions(){const oldFillBrand=fillBrand;fillBrand=function(){oldFillBrand();enhanceActiveSectionHighlightPicker()};const oldCollectBrand=collectBrand;collectBrand=function(){oldCollectBrand();collectActiveSectionHighlight()};const oldCurrentColorValues=currentColorValues;currentColorValues=function(){return{...oldCurrentColorValues(),activeSectionHighlightColor:activeSectionHighlightValue()}};const oldRenderSopList=renderSopList;renderSopList=function(){oldRenderSopList();decorateSopList()};const oldRenderSopForm=renderSopForm;renderSopForm=function(){oldRenderSopForm();renderSopRoleSelect();enhanceSopQuizStatus()};const oldPublish=publish;publish=async function(){if(saveSop(false)===false)return false;const autoCount=autoVersionPendingSops(),s=currentSop();if(s){sop_version.value=s.version;sop_lastUpdated.value=s.lastUpdated}syncJson();const ok=await oldPublish();if(ok!==false){const rolesSaved=await saveRoleListFromForm();const userSaved=false;if(autoCount&&status)status.textContent+=' Auto-versioned '+autoCount+' changed SOP'+(autoCount===1?'.':'s.');if(rolesSaved&&status)status.textContent+=' SOP assignment role list saved.';renderSopList();renderSectionOptions();renderDashboard();renderVersions();renderSopQuizStatus();renderAdvancedReset();enhanceUsers()}return ok};if($('publishBtn'))publishBtn.onclick=publish;if($('reloadBtn'))reloadBtn.onclick=async()=>{status.textContent='Reloading live portal data...';await loadData();await loadExtData();renderAll();status.textContent='Reloaded live portal data at '+new Date().toLocaleString()+'.'};setStatus=workflowStatus;if($('saveDraftBtn')){saveDraftBtn.textContent='Save';saveDraftBtn.onclick=saveCurrentSop}if($('submitReviewBtn'))submitReviewBtn.onclick=submitCurrentForReview;if($('approveBtn'))approveBtn.onclick=()=>setStatus('Approved','Approved');if($('rejectBtn'))rejectBtn.onclick=()=>setStatus('Rejected','Rejected');const oldRenderAll=renderAll;renderAll=function(){oldRenderAll();enhanceSopTab();enhanceSopQuizStatus();decorateSopList();enhanceRolesInSop();renderSopRoleChecks();enhanceUsers();enhanceActiveSectionHighlightPicker();addAdvancedResetPanel();renderAdvancedReset();if($('saveDraftBtn')){saveDraftBtn.textContent='Save';saveDraftBtn.onclick=saveCurrentSop}if($('submitReviewBtn'))submitReviewBtn.onclick=submitCurrentForReview;patchUserActions()};const oldSetTab=setTab;setTab=async function(tab){if(tab==='roles')tab='users';if(['backup','training','archive'].includes(tab)){if(tab==='backup'&&!hasAdmin())return alert('Admin role required.');if(tab==='training'&&!canViewReports())return alert('Admin portal access required.');document.querySelectorAll('.tab').forEach(x=>x.classList.add('hidden'));$('tab-'+tab).classList.remove('hidden');document.querySelectorAll('.admin-nav button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));if(tab==='backup')renderBackup();if(tab==='training'){$('trainingCenter').innerHTML='<p class="small">Loading latest checklist runs and quiz results...</p>';try{await refreshTrainingData()}catch(e){$('trainingCenter').innerHTML=`<p class="small">Could not load training reports: ${html(e.message||e)}</p>`;return}renderTraining()}if(tab==='archive')renderArchive();return}oldSetTab(tab);if(tab==='json'){addAdvancedResetPanel();renderAdvancedReset()}enhanceSopTab();enhanceSopQuizStatus();decorateSopList();enhanceRolesInSop();renderSopRoleChecks();enhanceUsers();enhanceActiveSectionHighlightPicker();if($('saveDraftBtn')){saveDraftBtn.textContent='Save';saveDraftBtn.onclick=saveCurrentSop}if($('submitReviewBtn'))submitReviewBtn.onclick=submitCurrentForReview;patchUserActions()};if($('dupSopBtn'))$('dupSopBtn').onclick=duplicateIntoSection;if($('archiveBtn'))$('archiveBtn').onclick=()=>setStatus('Archived','Archived');patchUserActions()}
  async function bootExt(){if(typeof DATA==='undefined'||!DATA){setTimeout(bootExt,250);return}addNav();addPanels();addAdvancedResetPanel();await loadExtData();enhanceImportDedupe();patchFunctions();enhanceSopTab();enhanceRolesInSop();renderSopRoleChecks();enhanceActiveSectionHighlightPicker();enhanceLogoUploadHelp();renderAll()}
